export function normalizeMemberName(name) {
  return (name || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ")
}

function lastNameSortKey(fullName) {
  const parts = (fullName || "").trim().split(/\s+/)
  return (parts[parts.length - 1] || "").toLowerCase()
}

function parseSheetNodes(nodes) {
  let currentCategory = null
  const rows = []
  if (!nodes || !nodes.length) {
    return rows
  }
  for (const n of nodes) {
    const rawName = (n.Name || "").trim()
    if (!rawName || rawName === "Name") {
      continue
    }
    if (CATEGORY_HEADERS.has(rawName)) {
      currentCategory = rawName
      continue
    }
    rows.push({
      category: currentCategory,
      name: rawName,
      position: (n.Position || "").trim(),
      company: (n.Company || "").trim(),
    })
  }
  return rows
}

function categorizeBrother(industry, recentPosition) {
  const text = `${industry || ""} ${recentPosition || ""}`.toLowerCase()

  if (/\bventure capital\b|\bvc\b/.test(text)) {
    return "Venture Capital"
  }
  if (/\b(attorney|paralegal|legal counsel|\blaw\b|\.law)\b/.test(text)) {
    return "Law"
  }
  if (
    /\b(hr |human resources|human capital|people operations|talent acquisition|recruiter)\b/.test(
      text
    )
  ) {
    return "Human Resources & Administration"
  }
  if (/\b(marketing|brand|growth|sales|account executive|communications)\b/.test(text)) {
    return "Marketing & Sales"
  }
  if (
    /\b(software|developer|engineer|data scientist|product manager|product management|technical program|cyber|devops|sre|analytics|machine learning|ml engineer|ui\/ux|ux designer)\b/.test(
      text
    )
  ) {
    return "Technology & PM"
  }
  if (/\b(consulting|consultant)\b/.test(text)) {
    return "Consulting"
  }
  if (/\b(operations|supply chain|logistics|procurement)\b/.test(text)) {
    return "Operations"
  }
  if (
    /\b(quant|finance|accounting|audit|investment banking|private equity|wealth|asset management|equity research|tax|fp&a|treasury|controller)\b/.test(
      text
    ) ||
    /\b(kpmg|deloitte|ey |pwc|p\.w\.c|big four)\b/.test(text)
  ) {
    return "Finance & Accounting"
  }
  return "Other"
}

/** Prefer company after the last "@" in the most recent role segment. */
export function parseCompanyFromPosition(recentPosition) {
  if (!recentPosition || typeof recentPosition !== "string") {
    return ""
  }
  const segments = recentPosition.split(",").map((s) => s.trim())
  for (let i = segments.length - 1; i >= 0; i--) {
    const seg = segments[i]
    if (seg.includes("@")) {
      return seg.split("@").pop().trim()
    }
  }
  return ""
}

function groupAndSerialize(rows) {
  const grouped = {}
  CATEGORY_ORDER.forEach((c) => {
    grouped[c] = []
  })
  rows.forEach((r) => {
    const cat = r.category || "Other"
    if (!grouped[cat]) {
      grouped[cat] = []
    }
    grouped[cat].push(r)
  })
  CATEGORY_ORDER.forEach((c) => {
    grouped[c].sort((a, b) =>
      lastNameSortKey(a.name).localeCompare(lastNameSortKey(b.name))
    )
  })
  const out = []
  CATEGORY_ORDER.forEach((cat) => {
    const people = grouped[cat] || []
    if (people.length === 0) {
      return
    }
    out.push({ Name: cat })
    people.forEach((p) => {
      out.push({
        Name: p.name,
        Position: p.position,
        Company: p.company,
      })
    })
  })
  return { nodes: out }
}

function collectExcelNames(ftRows, internRows) {
  const s = new Set()
  ;[ftRows, internRows].forEach((list) => {
    list.forEach((r) => s.add(normalizeMemberName(r.name)))
  })
  return s
}

/**
 * @param {{
 *   fullTimeNodes: Array,
 *   internshipNodes: Array,
 *   biosNodes: Array,
 * }} input
 */
export function buildCareers2026FromData({
  fullTimeNodes,
  internshipNodes,
  biosNodes,
}) {
  const ftRows = INCOMING_FULL_TIME_2026.filter(
    (r) => !REMOVED_NAMES.has(normalizeMemberName(r.name))
  )

  const internRowsRaw = parseSheetNodes(internshipNodes).filter(
    (r) => !REMOVED_NAMES.has(normalizeMemberName(r.name))
  )

  const ftNameSet = new Set(ftRows.map((r) => normalizeMemberName(r.name)))

  let internRows = internRowsRaw.filter(
    (r) => !ftNameSet.has(normalizeMemberName(r.name))
  )

  const excelNames = collectExcelNames(
    parseSheetNodes(fullTimeNodes),
    parseSheetNodes(internshipNodes)
  )

  const biosOnly = (biosNodes || [])
    .map((node) => {
      const first = (node.First_Name || "").trim()
      const last = (node.Last_Name || "").trim()
      if (!first || !last || first === "InsertFirstName") {
        return null
      }
      const full = `${first} ${last}`
      const norm = normalizeMemberName(full)
      if (REMOVED_NAMES.has(norm)) {
        return null
      }
      if (ftNameSet.has(norm) || excelNames.has(norm)) {
        return null
      }
      const recentPosition = (node.Recent_Position || "").trim()
      const industry = (node.Industry || "").trim()
      const company = parseCompanyFromPosition(recentPosition)
      return {
        category: categorizeBrother(industry, recentPosition),
        name: full,
        position: recentPosition || "—",
        company: company || "—",
      }
    })
    .filter(Boolean)

  internRows = internRows.concat(biosOnly)

  return {
    fullTime: groupAndSerialize(ftRows),
    internships: groupAndSerialize(internRows),
  }
}
